ExerciseHintSolution <ul> <li>Define a function with one label argument and one boolean argument</li> <li>Use <code>if</code>/<code>else</code> to change both the color and the text</li> <li>Give the boolean argument a default value so you can omit it sometimes</li> </ul> <pre><code>#let desk-status(label, free: true) = {
  let s = if free { [#label - available] } else { [#label - taken] }
  let c = if free { rgb("#2a9d8f") } else { rgb("#e76f51") }
  rect(
    fill: c,
    radius: 5pt,
    inset: (x: 10pt, y: 6pt),
    text(fill: white, s)
  )
}

#align(horizon, stack(
  spacing: 0.3cm,
  desk-status("Desk A"),
  desk-status("Desk B", free: false),
  desk-status("Desk C"),
))
</code></pre>

ExerciseHintSolution <ul> <li>Split the work into small reusable functions instead of writing one large block</li> <li>Use another function with <code>..notes</code>, then loop over these notes to build each card</li> </ul> <pre><code>#set page(fill: rgb("#f8f9fa"), width: 15cm, height: 10cm, margin: 0.5cm)

#let banner(label, fill) = {
  rect(
    fill: fill,
    radius: 999pt,
    inset: (x: 12pt, y: 6pt),
    text(weight: "bold", fill: white, label),
  )
}

#let note-list(..notes) = {
  for note in notes.pos() {
    [- #note \ ]
  }
}

#let task-card(title, color, ..notes) = {
  rect(fill: white, stroke: color, radius: 8pt, inset: 12pt, width: 9cm, [
    #text(weight: "bold", fill: color, title)
    #v(0.15cm)
    #note-list(..notes)
  ])
}

#banner("Release board", rgb("#264653"))
#task-card(
  "Homepage",
  rgb("#2a9d8f"),
  "Hero ready",
  "CTA checked",
  "Add final screenshot",
)
#task-card("Slides", rgb("#e9c46a"), "Add one chart", "Shorten intro")
#banner("1 item needs review", rgb("#e76f51"))
</code></pre>

ExerciseHintSolution <ul> <li>Write a <code>#show heading: it =&gt; ...</code> rule</li> <li>Use <code>it.body</code> and <code>it.level</code></li> <li>Use an <code>if</code>/<code>else</code> to change the card colors depending on the heading level</li> <li>Wrap each transformed heading in a full-width rounded <code>rect(...)</code></li> <li>Tip: use <code>#lorem(15)</code> to generate 15 random Lorem Ipsum words.</li> </ul> <pre><code>#set page(fill: rgb("#f8f9fa"), width: 15cm, height: 13cm)

#show heading: it =&gt; {
let fill = if it.level == 1 { rgb("#264653") } else { rgb("#e9c46a") }
let ink = if it.level == 1 { white } else { rgb("#264653") }
let line-fill = if it.level == 1 { white } else { rgb("#264653") }
let heading-size = if it.level == 1 { 14pt } else { 12pt }

    rect(fill: fill, radius: 8pt, inset: (x: 8pt, y: 10pt), width: 100%, [
      #underline(text(size: 9pt, fill: ink)[Section level #it.level], offset: 2pt)\
      #text(size: heading-size, weight: "bold", fill: ink)[#it.body]
    ])

}

= Kickoff plan
#lorem(15)

== Collect quotes
#lorem(15)

== Review export
#lorem(15)
</code></pre> <p>Question</p> <p>Having questions? Feedback? Feel free to ask!</p>
